package actor

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime/actor"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type SupervisorProxy struct {
	actor.UnimplementedSupervisorServer
	client actor.SupervisorClient
}

func init() {
	proxyutil.Register(&actor.Supervisor_ServiceDesc, NewSupervisorProxy)
}
func NewSupervisorProxy(cc grpc.ClientConnInterface) actor.SupervisorServer {
	return &SupervisorProxy{client: actor.NewSupervisorClient(cc)}
}
func (p *SupervisorProxy) Filter(ctx context.Context, in *runtime.Envelope) (*runtime.Envelope, error) {
	return proxyutil.ProxyMethod[runtime.Envelope, runtime.Envelope](p.client.Filter)(ctx, in)
}
func (p *SupervisorProxy) Load(ctx context.Context, in *runtime.LinkedBundle) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[runtime.LinkedBundle, emptypb.Empty](p.client.Load)(ctx, in)
}
func (p *SupervisorProxy) Unload(ctx context.Context, in *actor.UnloadRequest) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[actor.UnloadRequest, emptypb.Empty](p.client.Unload)(ctx, in)
}
